class Solution:
    def permute(self, nums):
        out = []
        used = [False] * len(nums)
        def dfs(path):
            if len(path) == len(nums):
                out.append(path[:])
                return
            for i, value in enumerate(nums):
                if used[i]:
                    continue
                used[i] = True
                path.append(value)
                dfs(path)
                path.pop()
                used[i] = False
        dfs([])
        return out
